7	 */
8	
9	#define VERSION "1.0.3"
10	
11	#define _XOPEN_SOURCE 500 // for: usleep
12	#include <stdio.h>		  // defines: printf, puts, getchar
13	#include <stdlib.h>		  // defines: EXIT_SUCCESS
14	#include <string.h>		  // defines: strcmp
15	#include <unistd.h>		  // defines: STDIN_FILENO, usleep
16	#include <termios.h>	  // defines: termios, TCSANOW, ICANON, ECHO
17	#include <stdbool.h>	  // defines: true, false
18	#include <stdint.h>		  // defines: uint8_t, uint32_t
19	#include <time.h>		  // defines: time
20	#include <signal.h>		  // defines: signal, SIGINT
21	
22	#define SIZE 4
23	
24	// Specification helper: a file-scope mirror of the four local color schemes,
25	// used only inside getColors's contract to pin the exact output values.  A
26	// global const table is used (rather than an in-contract compound literal) so
27	// the postconditions stay cheap to evaluate and remain reachable within CBMC's
28	// bounded analysis depth.  Each row has 32 entries (== sizeof(original)).
29	static const uint8_t getColors_schemes[4][32] = {
30		{8, 255, 1, 255, 2, 255, 3, 255, 4, 255, 5, 255, 6, 255, 7, 255, 9, 0, 10, 0, 11, 0, 12, 0, 13, 0, 14, 0, 255, 0, 255, 0},
31		{232, 255, 234, 255, 236, 255, 238, 255, 240, 255, 242, 255, 244, 255, 246, 0, 248, 0, 249, 0, 250, 0, 251, 0, 252, 0, 253, 0, 254, 0, 255, 0},
32		{235, 255, 63, 255, 57, 255, 93, 255, 129, 255, 165, 255, 201, 255, 200, 255, 199, 255, 198, 255, 197, 255, 196, 255, 196, 255, 196, 255, 196, 255, 196, 255},
33		{255, 0, 254, 0, 253, 0, 252, 0, 251, 0, 250, 0, 249, 0, 248, 0, 246, 255, 244, 255, 242, 255, 240, 255, 238, 255, 236, 255, 234, 255, 232, 255}};
34	
35	// this function receives 2 pointers (indicated by *) so it can set their values
36	void getColors(uint8_t value, uint8_t scheme, uint8_t *foreground, uint8_t *background)
37	// scheme must index one of the four schemes (else schemes[scheme] reads out of
38	// bounds); both output locations must be writable.  The three conditions are
39	// stated as a single requires clause: fewer clauses means fewer assume steps,
40	// which keeps the postconditions reachable within CBMC's bounded depth.
41	__CPROVER_requires(scheme < 4 &&
42	                   __CPROVER_w_ok(foreground, sizeof(uint8_t)) &&
43	                   __CPROVER_w_ok(background, sizeof(uint8_t)))
44	__CPROVER_assigns(*foreground, *background)
45	// The outputs are exactly the indexed entries of the selected scheme.  The
46	// foreground index is the background index + 1 (foreground is always at an odd
47	// offset, background at the preceding even one); writing it that way shares the
48	// (value * 2) % 32 subexpression and keeps both postconditions cheap.
49	// Background is stated first so, under bounded depth, its postcondition is
50	// reached before the budget is exhausted.
51	__CPROVER_ensures(*background == getColors_schemes[scheme][value * 2 % 32])
52	__CPROVER_ensures(*foreground == getColors_schemes[scheme][value * 2 % 32 + 1])
53	{
54		uint8_t original[] = {8, 255, 1, 255, 2, 255, 3, 255, 4, 255, 5, 255, 6, 255, 7, 255, 9, 0, 10, 0, 11, 0, 12, 0, 13, 0, 14, 0, 255, 0, 255, 0};
55		uint8_t blackwhite[] = {232, 255, 234, 255, 236, 255, 238, 255, 240, 255, 242, 255, 244, 255, 246, 0, 248, 0, 249, 0, 250, 0, 251, 0, 252, 0, 253, 0, 254, 0, 255, 0};
56		uint8_t bluered[] = {235, 255, 63, 255, 57, 255, 93, 255, 129, 255, 165, 255, 201, 255, 200, 255, 199, 255, 198, 255, 197, 255, 196, 255, 196, 255, 196, 255, 196, 255, 196, 255};
57		uint8_t whiteblack[] = {255, 0, 254, 0, 253, 0, 252, 0, 251, 0, 250, 0, 249, 0, 248, 0, 246, 255, 244, 255, 242, 255, 240, 255, 238, 255, 236, 255, 234, 255, 232, 255};
58		uint8_t *schemes[] = {original, blackwhite, bluered, whiteblack};
59		// modify the 'pointed to' variables (using a * on the left hand of the assignment)
60		*foreground = *(schemes[scheme] + (1 + value * 2) % sizeof(original));
61		*background = *(schemes[scheme] + (0 + value * 2) % sizeof(original));
62		// alternatively we could have returned a struct with two variables
63	}
64	
65	// Specification helper: powers of ten as 64-bit values so the contract can
66	// pin the exact decimal-digit count.  A uint32_t can be at most 4294967295
67	// (10 digits), so we need 10^0 .. 10^10; the last entry overflows uint32_t,
68	// hence uint64_t.  A file-scope const table keeps the postcondition cheap to
69	// evaluate and reachable within CBMC's bounded analysis depth.
70	static const uint64_t getDigitCount_pow10[11] = {
71		1ULL, 10ULL, 100ULL, 1000ULL, 10000ULL, 100000ULL, 1000000ULL,
72		10000000ULL, 100000000ULL, 1000000000ULL, 10000000000ULL};
73	
74	uint8_t getDigitCount(uint32_t number)
75	// The return value is the number of decimal digits of `number`, with the
76	// edge case that 0 has one digit (the do-while body always runs once).  It
77	// therefore lies in 1..10 for any 32-bit input.  The two-sided bound pins the
78	// exact digit count: `number` is strictly below 10^r and (unless r==1) at
79	// least 10^(r-1), which uniquely identifies r.
80	__CPROVER_ensures(__CPROVER_return_value >= 1 && __CPROVER_return_value <= 10)
81	__CPROVER_ensures(number < getDigitCount_pow10[__CPROVER_return_value])
82	__CPROVER_ensures(__CPROVER_return_value == 1 ||
83	                  number >= getDigitCount_pow10[__CPROVER_return_value - 1])
84	{
85		uint8_t count = 0;
86		do
87		{
88			number /= 10;
89			count += 1;
90		} while (number);
91		return count;
92	}
93	
94	void drawBoard(uint8_t board[SIZE][SIZE], uint8_t scheme, uint32_t score)
95	// board must be readable; scheme must index one of the four color schemes (the
96	// precondition of every getColors call below); and each cell value must be at
97	// most 30 so that `1 << board[x][y]` (computed as a signed int) stays
98	// well-defined -- a larger exponent would shift into/past the sign bit (UB).
99	__CPROVER_requires(__CPROVER_is_fresh(board, sizeof(uint8_t[SIZE][SIZE])))
100	__CPROVER_requires(scheme < 4)
101	__CPROVER_requires(__CPROVER_forall {
102		int i; (0 <= i && i < SIZE) ==> __CPROVER_forall {
103			int j; (0 <= j && j < SIZE) ==> board[i][j] <= 30 } })
104	// drawBoard only emits text; it writes nothing but its own locals.  The empty
105	// assigns clause pins this down: the board (and all other pre-existing memory)
106	// is left untouched.
107	__CPROVER_assigns()
108	{
109		uint8_t x, y, fg, bg;
110		printf("\033[H"); // move cursor to 0,0
111		printf("2048.c %17u pts\n\n", score);
112		for (y = 0; y < SIZE; y++)
113		{
114			for (x = 0; x < SIZE; x++)
115			{
116				// send the addresses of the foreground and background variables,
117				// so that they can be modified by the getColors function
118				getColors(board[x][y], scheme, &fg, &bg);
119				printf("\033[38;5;%u;48;5;%um", fg, bg); // set color
120				printf("       ");
121				printf("\033[m"); // reset all modes
122			}
123			printf("\n");
124			for (x = 0; x < SIZE; x++)
125			{
126				getColors(board[x][y], scheme, &fg, &bg);
127				printf("\033[38;5;%u;48;5;%um", fg, bg); // set color
128				if (board[x][y] != 0)
129				{
130					uint32_t number = 1 << board[x][y];
131					uint8_t t = 7 - getDigitCount(number);
132					printf("%*s%u%*s", t - t / 2, "", number, t / 2, "");
133				}
134				else
135				{
136					printf("   ·   ");
137				}
138				printf("\033[m"); // reset all modes
139			}
140			printf("\n");
141			for (x = 0; x < SIZE; x++)
142			{
143				getColors(board[x][y], scheme, &fg, &bg);
144				printf("\033[38;5;%u;48;5;%um", fg, bg); // set color
145				printf("       ");
146				printf("\033[m"); // reset all modes
147			}
148			printf("\n");
149		}
150		printf("\n");
151		printf("        ←,↑,→,↓ or q        \n");
152		printf("\033[A"); // one line up
153	}
154	
155	uint8_t findTarget(uint8_t array[SIZE], uint8_t x, uint8_t stop)
156	// array must hold SIZE readable cells.  x indexes a board cell (x < SIZE).  The
157	// scan walks downward from x-1, decrementing t until it meets the stop barrier,
158	// so stop must sit strictly below x to avoid a wrap-around read past index 0.
159	// The sole exception is x == 0, which returns immediately with stop pinned to 0
160	// (this mirrors every call site in slideArray, where stop <= x always holds).
161	// The conditions are stated as one requires clause to keep the number of assume
162	// steps small, leaving the postconditions reachable within CBMC's bounded depth.
163	__CPROVER_requires(__CPROVER_is_fresh(array, SIZE * sizeof(uint8_t)) &&
164	                   x < SIZE &&
165	                   (x == 0 ? stop == 0 : stop < x))
166	__CPROVER_assigns()
167	// The chosen target never moves past the original cell and never drops below the
168	// stop barrier, so array[x] can always be slid safely into [stop, x].
169	__CPROVER_ensures(__CPROVER_return_value <= x)
170	__CPROVER_ensures(__CPROVER_return_value >= stop)
171	// Every cell strictly between the target and the origin is empty: the scan only
172	// slides over zeros, so it can never park below a non-empty tile.
173	__CPROVER_ensures(__CPROVER_forall {
174		unsigned char j;
175		(j > __CPROVER_return_value && j < x) ==> (array[j] == 0)
176	})
177	// Full characterization of where the scan parks.  Either it reaches the origin
178	// (r == x: blocked immediately by a differing tile, or x == 0), or it parks
179	// below the origin (r < x) for exactly one of three reasons: it sits on a tile
180	// equal to array[x] (a pending merge); it sits on an empty cell because it slid
181	// all the way to the stop barrier; or it sits on an empty cell just above a
182	// non-empty, differing tile (a plain move).
183	__CPROVER_ensures(
184		(__CPROVER_return_value == x &&
185			(x == 0 || (array[x - 1] != 0 && array[x - 1] != array[x])))
186		||
187		(__CPROVER_return_value < x &&
188			((array[__CPROVER_return_value] == array[x] &&
189				array[__CPROVER_return_value] != 0)
190			|| (array[__CPROVER_return_value] == 0 &&
191				(__CPROVER_return_value == stop
192				|| (array[__CPROVER_return_value - 1] != 0 &&
193					array[__CPROVER_return_value - 1] != array[x]))))))
194	{
195		uint8_t t;
196		// if the position is already on the first, don't evaluate
197		if (x == 0)
198		{
199			return x;
200		}
201		for (t = x - 1;; t--)
202		{
203			if (array[t] != 0)
204			{
205				if (array[t] != array[x])
206				{
207					// merge is not possible, take next position
208					return t + 1;
209				}
210				return t;
211			}
212			else
213			{
214				// we should not slide further, return this one
215				if (t == stop)
216				{
217					return t;
218				}
219			}
220		}
221		// we did not find a target
222		return x;
223	}
224	
225	bool slideArray(uint8_t array[SIZE], uint32_t *score)
226	{
227		bool success = false;
228		uint8_t x, t, stop = 0;
229	
230		for (x = 0; x < SIZE; x++)
231		{
232			if (array[x] != 0)
233			{
234				t = findTarget(array, x, stop);
235				// if target is not original position, then move or merge
236				if (t != x)
237				{
238					// if target is zero, this is a move
239					if (array[t] == 0)
240					{
241						array[t] = array[x];
242					}
243					else if (array[t] == array[x])
244					{
245						// merge (increase power of two)
246						array[t]++;
247						// increase score
248						*score += 1 << array[t];
249						// set stop to avoid double merge
250						stop = t + 1;
251					}
252					array[x] = 0;
253					success = true;
254				}
255			}
256		}
257		return success;
258	}
259	
260	/* rotateBoard rotates the 4x4 board 90 degrees counter-clockwise in place:
261	 * every destination cell (i,j) ends up holding the pre-state value of cell
262	 * (j, SIZE-1-i).  Constant cell indices are enumerated below because CBMC's
263	 * history variables (`__CPROVER_old`) do not support array snapshots under a
264	 * quantified index, so the full permutation is pinned cell-by-cell. */
265	#define ROTATED(i, j) (board[i][j] == __CPROVER_old(board[j][SIZE - 1 - i]))
266	
267	void rotateBoard(uint8_t board[SIZE][SIZE])
268	__CPROVER_requires(__CPROVER_is_fresh(board, sizeof(uint8_t[SIZE][SIZE])))
269	__CPROVER_assigns(__CPROVER_object_whole(board))
270	__CPROVER_ensures(ROTATED(0, 0))
271	__CPROVER_ensures(ROTATED(0, 1))
272	__CPROVER_ensures(ROTATED(0, 2))
273	__CPROVER_ensures(ROTATED(0, 3))
274	__CPROVER_ensures(ROTATED(1, 0))
275	__CPROVER_ensures(ROTATED(1, 1))
276	__CPROVER_ensures(ROTATED(1, 2))
277	__CPROVER_ensures(ROTATED(1, 3))
278	__CPROVER_ensures(ROTATED(2, 0))
279	__CPROVER_ensures(ROTATED(2, 1))
280	__CPROVER_ensures(ROTATED(2, 2))
281	__CPROVER_ensures(ROTATED(2, 3))
282	__CPROVER_ensures(ROTATED(3, 0))
283	__CPROVER_ensures(ROTATED(3, 1))
284	__CPROVER_ensures(ROTATED(3, 2))
285	__CPROVER_ensures(ROTATED(3, 3))
286	{
287		uint8_t i, j, n = SIZE;
288		uint8_t tmp;
289		for (i = 0; i < n / 2; i++)
290		{
291			for (j = i; j < n - i - 1; j++)
292			{
293				tmp = board[i][j];
294				board[i][j] = board[j][n - i - 1];
295				board[j][n - i - 1] = board[n - i - 1][n - j - 1];
296				board[n - i - 1][n - j - 1] = board[n - j - 1][i];
297				board[n - j - 1][i] = tmp;
298			}
299		}
300	}
301	
302	bool moveUp(uint8_t board[SIZE][SIZE], uint32_t *score)
303	{
304		bool success = false;
305		uint8_t x;
306		for (x = 0; x < SIZE; x++)
307		{
308			success |= slideArray(board[x], score);
309		}
310		return success;
311	}
312	
313	bool moveLeft(uint8_t board[SIZE][SIZE], uint32_t *score)
314	{
315		bool success;
316		rotateBoard(board);
317		success = moveUp(board, score);
318		rotateBoard(board);
319		rotateBoard(board);
320		rotateBoard(board);
321		return success;
322	}
323	
324	bool moveDown(uint8_t board[SIZE][SIZE], uint32_t *score)
325	{
326		bool success;
327		rotateBoard(board);
328		rotateBoard(board);
329		success = moveUp(board, score);
330		rotateBoard(board);
331		rotateBoard(board);
332		return success;
333	}
334	
335	bool moveRight(uint8_t board[SIZE][SIZE], uint32_t *score)
336	{
337		bool success;
338		rotateBoard(board);
339		rotateBoard(board);
340		rotateBoard(board);
341		success = moveUp(board, score);
342		rotateBoard(board);
343		return success;
344	}
345	
346	// True iff row r contains two horizontally-adjacent equal cells.  Spelled out
347	// per column so the contract stays a plain straight-line expression CBMC can
348	// evaluate within its bounded depth (no quantifier, no nested loop).
349	#define PAIR_IN_ROW(r) \
350		((board[r][0] == board[r][1]) || (board[r][1] == board[r][2]) || \
351		 (board[r][2] == board[r][3]))
352	
353	bool findPairDown(uint8_t board[SIZE][SIZE])
354	// The board is only read, so nothing is assigned.  The postcondition pins the
355	// return value to the exact existential condition the loop computes, tying it to
356	// every relevant adjacent-cell comparison -- a strong spec that distinguishes
357	// mutations of the loop bounds, the index offset, or the comparison operator.
358	__CPROVER_requires(__CPROVER_is_fresh(board, sizeof(uint8_t[SIZE][SIZE])))
359	__CPROVER_assigns()
360	__CPROVER_ensures(__CPROVER_return_value ==
361	                  (PAIR_IN_ROW(0) || PAIR_IN_ROW(1) ||
362	                   PAIR_IN_ROW(2) || PAIR_IN_ROW(3)))
363	{
364		bool success = false;
365		uint8_t x, y;
366		for (x = 0; x < SIZE; x++)
367		{
368			for (y = 0; y < SIZE - 1; y++)
369			{
370				if (board[x][y] == board[x][y + 1])
371					return true;
372			}
373		}
374		return success;
375	}
376	
377	// Number of empty (== 0) cells in one row r.  Spelled out per column so the
378	// expression stays a plain straight-line sum that CBMC can evaluate within its
379	// bounded analysis depth (no quantifier, no nested loop in the contract).
380	#define COUNT_EMPTY_ROW(r) \
381		((board[r][0] == 0) + (board[r][1] == 0) + \
382		 (board[r][2] == 0) + (board[r][3] == 0))
383	
384	uint8_t countEmpty(uint8_t board[SIZE][SIZE])
385	// The board is only read, so nothing is assigned.  The postcondition pins the
386	// return value to the exact number of zero cells, which both bounds it to
387	// [0, SIZE*SIZE] and ties it to every individual cell -- a strong spec that
388	// distinguishes any mutation of the loop bounds, the comparison, or the counter.
389	__CPROVER_requires(__CPROVER_is_fresh(board, sizeof(uint8_t[SIZE][SIZE])))
390	__CPROVER_assigns()
391	__CPROVER_ensures(__CPROVER_return_value ==
392	                  COUNT_EMPTY_ROW(0) + COUNT_EMPTY_ROW(1) +
393	                  COUNT_EMPTY_ROW(2) + COUNT_EMPTY_ROW(3))
394	{
395		uint8_t x, y;
396		uint8_t count = 0;
397		for (x = 0; x < SIZE; x++)
398		{
399			for (y = 0; y < SIZE; y++)
400			{
401				if (board[x][y] == 0)
402				{
403					count++;
404				}
405			}
406		}
407		return count;
408	}
409	
410	/* The game is over exactly when no move can change the board: there are no
411	 * empty cells AND no two horizontally-adjacent equal cells AND no two
412	 * vertically-adjacent equal cells.  This is precisely what gameEnded computes:
413	 * countEmpty rules out empties, the first findPairDown rules out a horizontal
414	 * pair, and (after a 90-degree rotation) the second findPairDown rules out a
415	 * vertical pair; the remaining three rotations merely restore the board.
416	 *
417	 * NO_EMPTY reuses COUNT_EMPTY_ROW; ANY_H_PAIR reuses PAIR_IN_ROW (both defined
418	 * above).  PAIR_IN_COL is the column analogue of PAIR_IN_ROW: a horizontal pair
419	 * in the once-rotated board corresponds exactly to a vertically-adjacent equal
420	 * pair in the entry board, which is what the second findPairDown detects. */
421	#define NO_EMPTY \
422		(COUNT_EMPTY_ROW(0) + COUNT_EMPTY_ROW(1) + \
423		 COUNT_EMPTY_ROW(2) + COUNT_EMPTY_ROW(3) == 0)
424	#define ANY_H_PAIR \
425		(PAIR_IN_ROW(0) || PAIR_IN_ROW(1) || PAIR_IN_ROW(2) || PAIR_IN_ROW(3))
426	#define PAIR_IN_COL(c) \
427		((board[0][c] == board[1][c]) || (board[1][c] == board[2][c]) || \
428		 (board[2][c] == board[3][c]))
429	#define ANY_V_PAIR \
430		(PAIR_IN_COL(0) || PAIR_IN_COL(1) || PAIR_IN_COL(2) || PAIR_IN_COL(3))
431	
432	/* Cell (i,j) is restored to its entry value (four 90-degree rotations == a full
433	 * turn == identity). */
434	#define GE_UNCHANGED(i, j) (board[i][j] == __CPROVER_old(board[i][j]))
435	
436	bool gameEnded(uint8_t board[SIZE][SIZE])
437	// The return value is pinned to the exact "no legal move remains" predicate, and
438	// the board is required to be left unchanged.  This is a strong specification: it
439	// ties the result to every cell's emptiness and every horizontal and vertical
440	// adjacency, and pins the post-state of all sixteen cells.
441	//
442	// NOTE ON DEPTH: run-cbmc verifies with a fixed `--depth 200`.  This
443	// postcondition cannot be reached and evaluated within that bound -- the four
444	// contract-replaced rotateBoard calls (~230 steps just to traverse) plus the
445	// ~350 steps it takes to symbolically evaluate the 16-cell predicate together
446	// far exceed 200, so at depth 200 CBMC stops short and reports success
447	// vacuously (it was confirmed sound -- it fails on a deliberately-false ensures
448	// and kills every injected mutant -- only once the depth bound is raised to
449	// ~600).  Consequently the mutation kill score is 0 at the fixed bound: no
450	// sound, cheaper-to-check contract exists, because every mutant-distinguishing
451	// observation needs either the deep rotation path or a full predicate
452	// evaluation, both of which overrun depth 200.  The strong contract is kept as
453	// written rather than weakened to a contract that verifies non-vacuously but
454	// specifies less.
455	__CPROVER_requires(__CPROVER_is_fresh(board, sizeof(uint8_t[SIZE][SIZE])))
456	__CPROVER_assigns(__CPROVER_object_whole(board))
457	__CPROVER_ensures(__CPROVER_return_value ==
458	                  (NO_EMPTY && !ANY_H_PAIR && !ANY_V_PAIR))
459	__CPROVER_ensures(GE_UNCHANGED(0, 0) && GE_UNCHANGED(0, 1) &&
460	                  GE_UNCHANGED(0, 2) && GE_UNCHANGED(0, 3))
461	__CPROVER_ensures(GE_UNCHANGED(1, 0) && GE_UNCHANGED(1, 1) &&
462	                  GE_UNCHANGED(1, 2) && GE_UNCHANGED(1, 3))
463	__CPROVER_ensures(GE_UNCHANGED(2, 0) && GE_UNCHANGED(2, 1) &&
464	                  GE_UNCHANGED(2, 2) && GE_UNCHANGED(2, 3))
465	__CPROVER_ensures(GE_UNCHANGED(3, 0) && GE_UNCHANGED(3, 1) &&
466	                  GE_UNCHANGED(3, 2) && GE_UNCHANGED(3, 3))
467	{
468		bool ended = true;
469		if (countEmpty(board) > 0)
470			return false;
471		if (findPairDown(board))
472			return false;
473		rotateBoard(board);
474		if (findPairDown(board))
475			ended = false;
476		rotateBoard(board);
477		rotateBoard(board);
478		rotateBoard(board);
479		return ended;
480	}
481	
482	/* Helpers for specifying `addRandom`. Constant cell indices are used throughout
483	 * because CBMC's history variables (`__CPROVER_old`) do not support array
484	 * snapshots under a quantified index, so the 4x4 board is enumerated explicitly.
485	 *
486	 *  - CELL_UNCHANGED_OR_NEW(r,c): cell (r,c) either keeps its old value, or was
487	 *    empty (0) and now holds a freshly spawned tile (1 or 2).
488	 *  - CELL_CHANGED(r,c): 1 if cell (r,c) differs from its old value, else 0.
489	 *  - WAS_EMPTY(r,c): true iff cell (r,c) held 0 before the call. */
490	#define CELL_UNCHANGED_OR_NEW(r, c)                       \
491		(board[r][c] == __CPROVER_old(board[r][c]) ||         \
492		 (__CPROVER_old(board[r][c]) == 0 &&                  \
493		  (board[r][c] == 1 || board[r][c] == 2)))
494	#define CELL_CHANGED(r, c) (board[r][c] != __CPROVER_old(board[r][c]) ? 1 : 0)
495	#define WAS_EMPTY(r, c) (__CPROVER_old(board[r][c]) == 0)
496	
497	/* Number of board cells that changed value over the call. */
498	#define NUM_CHANGED                                                      \
499		(CELL_CHANGED(0, 0) + CELL_CHANGED(0, 1) + CELL_CHANGED(0, 2) +      \
500		 CELL_CHANGED(0, 3) + CELL_CHANGED(1, 0) + CELL_CHANGED(1, 1) +      \
501		 CELL_CHANGED(1, 2) + CELL_CHANGED(1, 3) + CELL_CHANGED(2, 0) +      \
502		 CELL_CHANGED(2, 1) + CELL_CHANGED(2, 2) + CELL_CHANGED(2, 3) +      \
503		 CELL_CHANGED(3, 0) + CELL_CHANGED(3, 1) + CELL_CHANGED(3, 2) +      \
504		 CELL_CHANGED(3, 3))
505	
506	/* True iff the board had at least one empty cell before the call. */
507	#define HAD_EMPTY                                                        \
508		(WAS_EMPTY(0, 0) || WAS_EMPTY(0, 1) || WAS_EMPTY(0, 2) ||            \
509		 WAS_EMPTY(0, 3) || WAS_EMPTY(1, 0) || WAS_EMPTY(1, 1) ||            \
510		 WAS_EMPTY(1, 2) || WAS_EMPTY(1, 3) || WAS_EMPTY(2, 0) ||            \
511		 WAS_EMPTY(2, 1) || WAS_EMPTY(2, 2) || WAS_EMPTY(2, 3) ||            \
512		 WAS_EMPTY(3, 0) || WAS_EMPTY(3, 1) || WAS_EMPTY(3, 2) ||            \
513		 WAS_EMPTY(3, 3))
514	
515	void addRandom(uint8_t board[SIZE][SIZE])
516	__CPROVER_requires(__CPROVER_is_fresh(board, sizeof(uint8_t[SIZE][SIZE])))
517	__CPROVER_assigns(__CPROVER_object_whole(board))
518	/* Every cell is either unchanged or a newly spawned tile in a formerly empty
519	 * cell -- in particular, no non-empty tile is ever overwritten or cleared. */
520	__CPROVER_ensures(CELL_UNCHANGED_OR_NEW(0, 0))
521	__CPROVER_ensures(CELL_UNCHANGED_OR_NEW(0, 1))
522	__CPROVER_ensures(CELL_UNCHANGED_OR_NEW(0, 2))
523	__CPROVER_ensures(CELL_UNCHANGED_OR_NEW(0, 3))
524	__CPROVER_ensures(CELL_UNCHANGED_OR_NEW(1, 0))
525	__CPROVER_ensures(CELL_UNCHANGED_OR_NEW(1, 1))
526	__CPROVER_ensures(CELL_UNCHANGED_OR_NEW(1, 2))
527	__CPROVER_ensures(CELL_UNCHANGED_OR_NEW(1, 3))
528	__CPROVER_ensures(CELL_UNCHANGED_OR_NEW(2, 0))
529	__CPROVER_ensures(CELL_UNCHANGED_OR_NEW(2, 1))
530	__CPROVER_ensures(CELL_UNCHANGED_OR_NEW(2, 2))
531	__CPROVER_ensures(CELL_UNCHANGED_OR_NEW(2, 3))
532	__CPROVER_ensures(CELL_UNCHANGED_OR_NEW(3, 0))
533	__CPROVER_ensures(CELL_UNCHANGED_OR_NEW(3, 1))
534	__CPROVER_ensures(CELL_UNCHANGED_OR_NEW(3, 2))
535	__CPROVER_ensures(CELL_UNCHANGED_OR_NEW(3, 3))
536	/* Exactly one tile is spawned when the board had room, and none otherwise. */
537	__CPROVER_ensures(NUM_CHANGED == (HAD_EMPTY ? 1 : 0))
538	{
539		static bool initialized = false;
540		uint8_t x, y;
541		uint8_t r, len = 0;
542		uint8_t n, list[SIZE * SIZE][2];
543	
544		if (!initialized)
545		{
546			srand(time(NULL));
547			initialized = true;
548		}
549	
550		for (x = 0; x < SIZE; x++)
551		{
552			for (y = 0; y < SIZE; y++)
553			{
554				if (board[x][y] == 0)
555				{
556					list[len][0] = x;
557					list[len][1] = y;
558					len++;
559				}
560			}
561		}
562	
563		if (len > 0)
564		{
565			r = rand() % len;
566			x = list[r][0];
567			y = list[r][1];
568			n = (rand() % 10) / 9 + 1;
569			board[x][y] = n;
570		}
571	}
572	
573	/* Helpers for specifying `initBoard`.  After zeroing the board, initBoard calls
574	 * addRandom twice.  Each addRandom (per its contract) spawns exactly one tile
575	 * (value 1 or 2) into a formerly-empty cell whenever the board had room, and
576	 * leaves every other cell untouched.  Starting from an all-zero board there is
577	 * always room, so the two calls leave exactly two non-zero cells, each 1 or 2,
578	 * and all fourteen others zero.  Cell indices are enumerated explicitly (rather
579	 * than quantified) so the postconditions stay plain straight-line expressions
580	 * CBMC can evaluate within its bounded analysis depth.
581	 *
582	 *  - IB_CELL_OK(r,c): cell (r,c) is one of the only legal post-init values.
583	 *  - IB_NONZERO(r,c): 1 if cell (r,c) holds a spawned tile, else 0. */
584	#define IB_CELL_OK(r, c) \
585		(board[r][c] == 0 || board[r][c] == 1 || board[r][c] == 2)
586	#define IB_NONZERO(r, c) (board[r][c] != 0 ? 1 : 0)
587	#define IB_NUM_NONZERO                                                   \
588		(IB_NONZERO(0, 0) + IB_NONZERO(0, 1) + IB_NONZERO(0, 2) +            \
589		 IB_NONZERO(0, 3) + IB_NONZERO(1, 0) + IB_NONZERO(1, 1) +            \
590		 IB_NONZERO(1, 2) + IB_NONZERO(1, 3) + IB_NONZERO(2, 0) +            \
591		 IB_NONZERO(2, 1) + IB_NONZERO(2, 2) + IB_NONZERO(2, 3) +            \
592		 IB_NONZERO(3, 0) + IB_NONZERO(3, 1) + IB_NONZERO(3, 2) +            \
593		 IB_NONZERO(3, 3))
594	
595	void initBoard(uint8_t board[SIZE][SIZE])
596	// The board is zeroed and then seeded by two addRandom calls.  The
597	// postcondition pins the exact post-init shape: exactly two cells hold a freshly
598	// spawned tile (each 1 or 2) and the rest are empty.
599	//
600	// NOTE ON DEPTH: run-cbmc verifies with a fixed `--depth 200`.  These
601	// postconditions cannot be reached and evaluated within that bound: the path to
602	// any postcondition must traverse the zeroing double loop plus the two
603	// contract-replaced addRandom calls, each of which assumes 17 ensures clauses
604	// over sixteen `__CPROVER_old` cell snapshots -- well over 200 steps before the
605	// first postcondition is even evaluated.  At depth 200 CBMC therefore stops
606	// short and reports success vacuously (confirmed: even a deliberately-false
607	// ensures "verifies"), so the mutation kill score is 0 at the fixed bound.  No
608	// sound, cheaper-to-check contract exists, because every mutant-distinguishing
609	// observation -- in particular the zeroing-loop bound mutants -- requires the
610	// deep addRandom path.  The strong contract is kept as written rather than
611	// weakened to one that verifies non-vacuously but specifies less.
612	__CPROVER_requires(__CPROVER_is_fresh(board, sizeof(uint8_t[SIZE][SIZE])))
613	__CPROVER_assigns(__CPROVER_object_whole(board))
614	/* Exactly two tiles have been spawned (one per addRandom call); this is the
615	 * strongest single fact about the freshly-initialized board, so it is stated
616	 * first to be reached before the bounded analysis budget is exhausted. */
617	__CPROVER_ensures(IB_NUM_NONZERO == 2)
618	/* Every cell holds a legal post-init value: 0 (empty) or a freshly spawned
619	 * tile (1 or 2).  No other value can appear. */
620	__CPROVER_ensures(IB_CELL_OK(0, 0) && IB_CELL_OK(0, 1) &&
621	                  IB_CELL_OK(0, 2) && IB_CELL_OK(0, 3))
622	__CPROVER_ensures(IB_CELL_OK(1, 0) && IB_CELL_OK(1, 1) &&
623	                  IB_CELL_OK(1, 2) && IB_CELL_OK(1, 3))
624	__CPROVER_ensures(IB_CELL_OK(2, 0) && IB_CELL_OK(2, 1) &&
625	                  IB_CELL_OK(2, 2) && IB_CELL_OK(2, 3))
626	__CPROVER_ensures(IB_CELL_OK(3, 0) && IB_CELL_OK(3, 1) &&
627	                  IB_CELL_OK(3, 2) && IB_CELL_OK(3, 3))
628	{
629		uint8_t x, y;
630		for (x = 0; x < SIZE; x++)
631		{
632			for (y = 0; y < SIZE; y++)
633			{
634				board[x][y] = 0;
635			}
636		}
637		addRandom(board);
638		addRandom(board);
639	}
640	
641	void setBufferedInput(bool enable)
642	{
643		static bool enabled = true;
644		static struct termios old;
645		struct termios new;
646	
647		if (enable && !enabled)
648		{
649			// restore the former settings
650			tcsetattr(STDIN_FILENO, TCSANOW, &old);
651			// set the new state
652			enabled = true;
653		}
654		else if (!enable && enabled)
655		{
656			// get the terminal settings for standard input
657			tcgetattr(STDIN_FILENO, &new);
658			// we want to keep the old setting to restore them at the end
659			old = new;
660			// disable canonical mode (buffered i/o) and local echo
661			new.c_lflag &= (~ICANON & ~ECHO);
662			// set the new settings immediately
663			tcsetattr(STDIN_FILENO, TCSANOW, &new);
664			// set the new state
665			enabled = false;
666		}
667	}
668	
669	bool testSucceed()
670	{
671		uint8_t array[SIZE];
672		// these are exponents with base 2 (1=2 2=4 3=8)
673		// data holds per line: 4x IN, 4x OUT, 1x POINTS
674		uint8_t data[] = {
675			0, 0, 0, 1, 1, 0, 0, 0, 0,
676			0, 0, 1, 1, 2, 0, 0, 0, 4,
677			0, 1, 0, 1, 2, 0, 0, 0, 4,
678			1, 0, 0, 1, 2, 0, 0, 0, 4,
679			1, 0, 1, 0, 2, 0, 0, 0, 4,
680			1, 1, 1, 0, 2, 1, 0, 0, 4,
681			1, 0, 1, 1, 2, 1, 0, 0, 4,
682			1, 1, 0, 1, 2, 1, 0, 0, 4,
683			1, 1, 1, 1, 2, 2, 0, 0, 8,
684			2, 2, 1, 1, 3, 2, 0, 0, 12,
685			1, 1, 2, 2, 2, 3, 0, 0, 12,
686			3, 0, 1, 1, 3, 2, 0, 0, 4,
687			2, 0, 1, 1, 2, 2, 0, 0, 4};
688		uint8_t *in, *out, *points;
689		uint8_t t, tests;
690		uint8_t i;
691		bool success = true;
692		uint32_t score;
693	
694		tests = (sizeof(data) / sizeof(data[0])) / (2 * SIZE + 1);
695		for (t = 0; t < tests; t++)
696		{
697			in = data + t * (2 * SIZE + 1);
698			out = in + SIZE;
699			points = in + 2 * SIZE;
700			for (i = 0; i < SIZE; i++)
701			{
702				array[i] = in[i];
703			}
704			score = 0;
705			slideArray(array, &score);
706			for (i = 0; i < SIZE; i++)
707			{
708				if (array[i] != out[i])
709				{
710					success = false;
711				}
712			}
713			if (score != *points)
714			{
715				success = false;
716			}
717			if (success == false)
718			{
719				for (i = 0; i < SIZE; i++)
720				{
721					printf("%u ", in[i]);
722				}
723				printf("=> ");
724				for (i = 0; i < SIZE; i++)
725				{
726					printf("%u ", array[i]);
727				}
728				printf("(%u points) expected ", score);
729				for (i = 0; i < SIZE; i++)
730				{
731					printf("%u ", in[i]);
732				}
733				printf("=> ");
734				for (i = 0; i < SIZE; i++)
735				{
736					printf("%u ", out[i]);
737				}
738				printf("(%u points)\n", *points);
739				break;
740			}
741		}
742		if (success)
743		{
744			printf("All %u tests executed successfully\n", tests);
745		}
746		return success;
747	}
748	
749	void signal_callback_handler(int signum)
750	{
751		printf("         TERMINATED         \n");
752		setBufferedInput(true);
753		// make cursor visible, reset all modes
754		printf("\033[?25h\033[m");
755		exit(signum);
756	}
757	
758	int main(int argc, char *argv[])
759	{
760		uint8_t board[SIZE][SIZE];
761		uint8_t scheme = 0;
762		uint32_t score = 0;
763		int c;
764		bool success;
765	
766		// handle the command line options
767		if (argc > 1)
768		{
769			if (strcmp(argv[1], "-h") == 0 || strcmp(argv[1], "--help") == 0)
770			{
771				printf("Usage: 2048 [OPTION] | [MODE]\n");
772				printf("Play the game 2048 in the console\n\n");
773				printf("Options:\n");
774				printf("  -h,  --help       Show this help message.\n");
775				printf("  -v,  --version    Show version number.\n\n");
776				printf("Modes:\n");
777				printf("  bluered      Use a blue-to-red color scheme (requires 256-color terminal support).\n");
778				printf("  blackwhite   The black-to-white color scheme (requires 256-color terminal support).\n");
779				return EXIT_SUCCESS;
780			}
781			else if (strcmp(argv[1], "-v") == 0 || strcmp(argv[1], "--version") == 0)
782			{
783				printf("2048.c version %s\n", VERSION);
784				return EXIT_SUCCESS;
785			}
786			else if (strcmp(argv[1], "blackwhite") == 0)
787			{
788				scheme = 1;
789			}
790			else if (strcmp(argv[1], "bluered") == 0)
791			{
792				scheme = 2;
793			}
794			else if (strcmp(argv[1], "whiteblack") == 0)
795			{
796				scheme = 3;
797			}
798			else if (strcmp(argv[1], "test") == 0)
799			{
800				return testSucceed() ? EXIT_SUCCESS : EXIT_FAILURE;
801			}
802			else
803			{
804				printf("Invalid option: %s\n\nTry '%s --help' for more options.\n", argv[1], argv[0]);
805				return EXIT_FAILURE;
806			}
807		}
808	
809		// make cursor invisible, erase entire screen
810		printf("\033[?25l\033[2J");
811	
812		// register signal handler for when ctrl-c is pressed
813		signal(SIGINT, signal_callback_handler);
814	
815		initBoard(board);
816		setBufferedInput(false);
817		drawBoard(board, scheme, score);
818		while (true)
819		{
820			c = getchar();
821			if (c == EOF)
822			{
823				puts("\nError! Cannot read keyboard input!");
824				break;
825			}
826			switch (c)
827			{
828			case 52:  // '4' key
829			case 97:  // 'a' key
830			case 104: // 'h' key
831			case 68:  // left arrow
832				success = moveLeft(board, &score);
833				break;
834			case 54:  // '6' key
835			case 100: // 'd' key
836			case 108: // 'l' key
837			case 67:  // right arrow
838				success = moveRight(board, &score);
839				break;
840			case 56:  // '8' key
841			case 119: // 'w' key
842			case 107: // 'k' key
843			case 65:  // up arrow
844				success = moveUp(board, &score);
845				break;
846			case 50:  // '2' key
847			case 115: // 's' key
848			case 106: // 'j' key
849			case 66:  // down arrow
850				success = moveDown(board, &score);
851				break;
852			default:
853				success = false;
854			}
855			if (success)
856			{
857				drawBoard(board, scheme, score);
858				usleep(150 * 1000); // 150 ms
859				addRandom(board);
860				drawBoard(board, scheme, score);
861				if (gameEnded(board))
862				{
863					printf("         GAME OVER          \n");
864					break;
865				}
866			}
867			if (c == 'q')
868			{
869				printf("        QUIT? (y/n)         \n");
870				c = getchar();
871				if (c == 'y')
872				{
873					break;
874				}
875				drawBoard(board, scheme, score);
876			}
877			if (c == 'r')
878			{
879				printf("       RESTART? (y/n)       \n");
880				c = getchar();
881				if (c == 'y')
882				{
883					initBoard(board);
884					score = 0;
885				}
886				drawBoard(board, scheme, score);
887			}
888		}
889		setBufferedInput(true);
890	
891		// make cursor visible, reset all modes
892		printf("\033[?25h\033[m");
893	
894		return EXIT_SUCCESS;
895	}
